export interface BaseEntity {
  id: string;
  createdAt: Date;
  updatedAt: Date;
}

export interface Repository<T extends BaseEntity> {
  findById(id: string): Promise<T | null>;
  findAll(): Promise<T[]>;
  create(entity: Omit<T, 'id' | 'createdAt' | 'updatedAt'>): Promise<T>;
  update(id: string, entity: Partial<Omit<T, 'id' | 'createdAt'>>): Promise<T>;
  delete(id: string): Promise<boolean>;
  findByCondition(condition: Partial<T>): Promise<T[]>;
}

export abstract class BaseRepository<T extends BaseEntity> implements Repository<T> {
  protected abstract collection: Map<string, T>;

  async findById(id: string): Promise<T | null> {
    return this.collection.get(id) || null;
  }

  async findAll(): Promise<T[]> {
    return Array.from(this.collection.values());
  }

  async create(entity: Omit<T, 'id' | 'createdAt' | 'updatedAt'>): Promise<T> {
    const now = new Date();
    const newEntity = {
      ...entity,
      id: crypto.randomUUID(),
      createdAt: now,
      updatedAt: now
    } as T;
    this.collection.set(newEntity.id, newEntity);
    return newEntity;
  }

  async update(id: string, updates: Partial<Omit<T, 'id' | 'createdAt'>>): Promise<T> {
    const existing = await this.findById(id);
    if (!existing) throw new Error('Entity not found');
    const updated = { ...existing, ...updates, updatedAt: new Date() } as T;
    this.collection.set(id, updated);
    return updated;
  }

  async delete(id: string): Promise<boolean> {
    return this.collection.delete(id);
  }

  async findByCondition(condition: Partial<T>): Promise<T[]> {
    return Array.from(this.collection.values()).filter(entity =>
      Object.entries(condition).every(([key, value]) => entity[key] === value)
    );
  }
}

type AppEvent =
  | { type: 'USER_LOGIN'; userId: string; timestamp: Date }
  | { type: 'USER_LOGOUT'; userId: string; reason: 'manual' | 'timeout' }
  | { type: 'ORDER_CREATED'; orderId: string; amount: number; currency: string }
  | { type: 'PAYMENT_FAILED'; paymentId: string; errorCode: string; retryable: boolean }
  | { type: 'SYSTEM_ERROR'; error: Error; context: Record<string, unknown> };

class EventDispatcher {
  private handlers: Map<string, Set<(event: any) => void>> = new Map();

  subscribe(eventType: string, handler: (event: any) => void): void {
    if (!this.handlers.has(eventType)) {
      this.handlers.set(eventType, new Set());
    }
    this.handlers.get(eventType)!.add(handler);
  }

  unsubscribe(eventType: string, handler: (event: any) => void): void {
    this.handlers.get(eventType)?.delete(handler);
  }

  async dispatch(event: AppEvent): Promise<void> {
    const handlers = this.handlers.get(event.type);
    if (handlers) {
      for (const handler of handlers) {
        try {
          await handler(event);
        } catch (error) {
          console.error(`Error handling event ${event.type}:`, error);
        }
      }
    }
  }
}

export const dispatcher = new EventDispatcher();

function LogExecutionTime(target: any, propertyKey: string, descriptor: PropertyDescriptor) {
  const originalMethod = descriptor.value;

  descriptor.value = async function (...args: any[]) {
    const startTime = performance.now();
    console.log(`Starting ${propertyKey}...`);

    try {
      const result = await originalMethod.apply(this, args);
      const endTime = performance.now();
      console.log(`Finished ${propertyKey} in ${(endTime - startTime).toFixed(2)}ms`);
      return result;
    } catch (error) {
      console.error(`Error in ${propertyKey}:`, error);
      throw error;
    }
  };

  return descriptor;
}

function ValidateInput(schema: ZodSchema) {
  return function (target: any, propertyKey: string, descriptor: PropertyDescriptor) {
    const originalMethod = descriptor.value;

    descriptor.value = function (...args: any[]) {
      const validationResult = schema.safeParse(args[0]);
      if (!validationResult.success) {
        throw new ValidationError('Validation failed', validationResult.error);
      }
      return originalMethod.apply(this, args);
    };

    return descriptor;
  };
}

export { LogExecutionTime, ValidateInput };

abstract class BaseWorkflow<TInput, TOutput> {
  protected abstract validate(input: TInput): boolean;
  protected abstract executeStep1(input: TInput): any;
  protected abstract executeStep2(context: any): any;
  protected abstract executeStep3(context: any): TOutput;
  protected abstract transformOutput(result: any): TOutput;

  async run(input: TInput): Promise<TOutput> {
    console.log('Workflow started');

    if (!this.validate(input)) {
      throw new WorkflowError('Validation failed');
    }

    try {
      const step1Result = this.executeStep1(input);
      const step2Result = this.executeStep2(step1Result);
      const step3Result = this.executeStep3(step2Result);
      const output = this.transformOutput(step3Result);

      console.log('Workflow completed successfully');
      return output;
    } catch (error) {
      console.error('Workflow failed:', error);
      throw new WorkflowError('Workflow execution failed', error);
    }
  }

  protected logProgress(step: string, details?: any): void {
    console.log(`[${new Date().toISOString()}] ${step}:`, details);
  }
}

export { BaseWorkflow, WorkflowError };

import { Subject, BehaviorSubject, combineLatest, map, filter, debounceTime } from 'rxjs';

class UserActionObservable {
  private actionSubject = new Subject<UserAction>();
  private isActiveSubject = new BehaviorSubject<boolean>(true);

  readonly userActions$ = this.actionSubject.asObservable();
  readonly isActive$ = this.isActiveSubject.asObservable();

  pushAction(action: UserAction): void {
    this.actionSubject.next(action);
  }

  setInactive(): void {
    this.isActiveSubject.next(false);
  }

  getActiveLoginActions() {
    return combineLatest([this.userActions$, this.isActive$]).pipe(
      filter(([actions, isActive]) => isActive),
      map(([actions, _]) => actions.filter(a => a.type === 'LOGIN')),
      debounceTime(300)
    );
  }

  getUserActivitySummary() {
    return this.userActions$.pipe(
      filter(() => this.isActiveSubject.getValue()),
      groupBy(action => action.userId),
      switchMap(userGroup => userGroup.pipe(
        map(action => ({
          userId: action.userId,
          lastAction: action.timestamp,
          actionCount: userGroup.pipe(count()).subscribe()
        }))
      ))
    );
  }
}

export type UserAction = {
  type: 'LOGIN' | 'LOGOUT' | 'CLICK' | 'VIEW';
  userId: string;
  timestamp: Date;
  metadata?: Record<string, any>;
};

interface ServiceFactory<T> {
  create(): T;
}

type ServiceMap = Map<string, ServiceFactory<any>>;

class DependencyContainer {
  private services: ServiceMap = new Map();
  private instances: Map<string, any> = new Map();

  register<T>(token: string, factory: ServiceFactory<T>): void {
    this.services.set(token, factory);
  }

  registerSingleton<T>(token: string, factory: () => T): void {
    this.register(token, { create: () => {
      if (!this.instances.has(token)) {
        this.instances.set(token, factory());
      }
      return this.instances.get(token);
    }});
  }

  resolve<T>(token: string): T {
    const factory = this.services.get(token);
    if (!factory) {
      throw new Error(`Service ${token} not registered`);
    }
    return factory.create();
  }

  has(token: string): boolean {
    return this.services.has(token);
  }

  reset(): void {
    this.instances.clear();
  }
}

// Usage example
const container = new DependencyContainer();
container.registerSingleton('logger', () => new ConsoleLogger());
container.registerSingleton('database', () => new DatabaseConnection(container.resolve('logger')));
container.register('userService', () => new UserService(container.resolve('database'), container.resolve('logger')));

interface PricingStrategy {
  calculatePrice(basePrice: number, context: PricingContext): number;
  getName(): string;
}

interface PricingContext {
  userId: string;
  itemCount: number;
  membershipLevel: 'basic' | 'premium' | 'vip';
  isFirstPurchase: boolean;
  cartTotal: number;
}

class VolumeDiscountStrategy implements PricingStrategy {
  getName(): string { return 'Volume Discount'; }

  calculatePrice(basePrice: number, context: PricingContext): number {
    if (context.itemCount >= 10) return basePrice * 0.8;
    if (context.itemCount >= 5) return basePrice * 0.9;
    return basePrice;
  }
}

class MembershipDiscountStrategy implements PricingStrategy {
  getName(): string { return 'Membership Discount'; }

  calculatePrice(basePrice: number, context: PricingContext): number {
    switch (context.membershipLevel) {
      case 'vip': return basePrice * 0.7;
      case 'premium': return basePrice * 0.85;
      default: return basePrice;
    }
  }
}

class NewUserDiscountStrategy implements PricingStrategy {
  getName(): string { return 'New User Discount'; }

  calculatePrice(basePrice: number, context: PricingContext): number {
    return context.isFirstPurchase ? basePrice * 0.9 : basePrice;
  }
}

class PricingEngine {
  private strategies: PricingStrategy[] = [];

  addStrategy(strategy: PricingStrategy): void {
    this.strategies.push(strategy);
  }

  calculateFinalPrice(basePrice: number, context: PricingContext): number {
    let finalPrice = basePrice;
    for (const strategy of this.strategies) {
      finalPrice = strategy.calculatePrice(finalPrice, context);
    }
    return Math.max(finalPrice, 0);
  }
}

interface ContentNode {
  render(): string;
  getDepth(): number;
  getChildCount(): number;
  findNodeById(id: string): ContentNode | null;
}

class LeafNode implements ContentNode {
  constructor(
    private id: string,
    private type: 'text' | 'image' | 'video',
    private content: string,
    private depth: number = 0
  ) {}

  render(): string {
    switch (this.type) {
      case 'text': return `<p>${this.content}</p>`;
      case 'image': return `<img src="${this.content}" />`;
      case 'video': return `<video src="${this.content}"></video>`;
    }
  }

  getDepth(): number { return this.depth; }
  getChildCount(): number { return 0; }
  findNodeById(id: string): ContentNode | null {
    return this.id === id ? this : null;
  }
}

class CompositeNode implements ContentNode {
  private children: ContentNode[] = [];

  constructor(private id: string, private depth: number = 0) {}

  addChild(child: ContentNode): void {
    child['depth'] = this.depth + 1;
    this.children.push(child);
  }

  render(): string {
    return `<div id="${this.id}">${this.children.map(c => c.render()).join('')}</div>`;
  }

  getDepth(): number { return this.depth; }
  getChildCount(): number { return this.children.length; }
  findNodeById(id: string): ContentNode | null {
    if (this.id === id) return this;
    return this.children.find(c => c.findNodeById(id))?.findNodeById(id) || null;
  }
}
